import React, { useState, useEffect } from 'react';
import { db } from './firebase';
import { doc, getDoc, writeBatch, collection, getDocs } from "firebase/firestore";

const AdminPanel = ({ setIsSidebarOpen, fixedSubjects }) => {
  const [selectedSubjectForUpload, setSelectedSubjectForUpload] = useState("");
    const [csvContent, setCsvContent] = useState("");
      const [isUploading, setIsUploading] = useState(false);
        const [duplicateQuestionsStack, setDuplicateQuestionsStack] = useState([]);
          const [freshQuestionsStack, setFreshQuestionsStack] = useState([]);
            const [feedbacks, setFeedbacks] = useState([]);

              // Fetch Feedbacks
                useEffect(() => {
                    const fetchFeedback = async () => {
                          const snap = await getDocs(collection(db, "feedbacks"));
                                setFeedbacks(snap.docs.map(d => ({ id: d.id, ...d.data() })));
                                    };
                                        fetchFeedback();
                                          }, []);

                                            const handleFileChange = (e) => {
                                                const file = e.target.files[0];
                                                    if (!file) return;

                                                        const reader = new FileReader();
                                                            reader.onload = async (evt) => {
                                                                  const content = evt.target.result;
                                                                        setCsvContent(content);

                                                                              if (!selectedSubjectForUpload) {
                                                                                      alert("Bhai, pehle 'Subject Channel' select karo!");
                                                                                              return;
                                                                                                    }

                                                                                                          const metaRef = doc(db, "subject_meta", selectedSubjectForUpload);
                                                                                                                const metaSnap = await getDoc(metaRef);
                                                                                                                      let currentUnits = [], currentChunksConfig = {};
                                                                                                                            if (metaSnap.exists()) {
                                                                                                                                    currentUnits = metaSnap.data().units || [];
                                                                                                                                            currentChunksConfig = metaSnap.data().chunksConfig || {};
                                                                                                                                                  }

                                                                                                                                                        const existingTextsSet = new Set();
                                                                                                                                                              for (const u of currentUnits) {
                                                                                                                                                                      const numC = currentChunksConfig[u] || 0;
                                                                                                                                                                              for (let c = 0; c < numC; c++) {
                                                                                                                                                                                        const cSnap = await getDoc(doc(db, "subject_meta", `${selectedSubjectForUpload}_${u}_chunk_${c}`));
                                                                                                                                                                                                  if (cSnap.exists()) {
                                                                                                                                                                                                              (cSnap.data().questions || []).forEach(q => {
                                                                                                                                                                                                                            existingTextsSet.add(q.questionText.toLowerCase().trim().replace(/\s+/g, ''));
                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                      const regex = /,(?=(?:(?:[^"]*"){2})*[^"]*$)/;
                                                                                                                                                                                                                                                                            const lines = content.split('\n').filter(l => l.trim());
                                                                                                                                                                                                                                                                                  const headers = lines[0].toLowerCase().split(',').map(h => h.trim().replace(/^"|"$/g, ''));
                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                              const map = {
                                                                                                                                                                                                                                                                                                      unit: headers.indexOf('topic') !== -1 ? headers.indexOf('topic') : headers.indexOf('unit'),
                                                                                                                                                                                                                                                                                                              qText: headers.indexOf('question_text') !== -1 ? headers.indexOf('question_text') : headers.indexOf('question'),
                                                                                                                                                                                                                                                                                                                      a: headers.indexOf('option_a'), b: headers.indexOf('option_b'), c: headers.indexOf('option_c'), d: headers.indexOf('option_d'),
                                                                                                                                                                                                                                                                                                                              ans: headers.indexOf('correct_option') !== -1 ? headers.indexOf('correct_option') : headers.indexOf('answer'),
                                                                                                                                                                                                                                                                                                                                      tags: headers.indexOf('tags'), expl: headers.indexOf('explanation')
                                                                                                                                                                                                                                                                                                                                            };

                                                                                                                                                                                                                                                                                                                                                  const freshDetected = [];
                                                                                                                                                                                                                                                                                                                                                        const duplicatesDetected = [];

                                                                                                                                                                                                                                                                                                                                                              for (let i = 1; i < lines.length; i++) {
                                                                                                                                                                                                                                                                                                                                                                      const cols = lines[i].split(regex).map(c => c.trim().replace(/^"|"$/g, ''));
                                                                                                                                                                                                                                                                                                                                                                              if (cols.length >= 7) {
                                                                                                                                                                                                                                                                                                                                                                                        const qText = cols[map.qText];
                                                                                                                                                                                                                                                                                                                                                                                                  if (!qText) continue;

                                                                                                                                                                                                                                                                                                                                                                                                            const cleanText = qText.toLowerCase().trim().replace(/\s+/g, '');
                                                                                                                                                                                                                                                                                                                                                                                                                      const unitName = cols[map.unit] || "General";

                                                                                                                                                                                                                                                                                                                                                                                                                                const qObject = {
                                                                                                                                                                                                                                                                                                                                                                                                                                            qId: Math.random().toString(36).substring(2, 11) + "_" + Date.now(),
                                                                                                                                                                                                                                                                                                                                                                                                                                                        subject: selectedSubjectForUpload,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    unit: [unitName],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                tags: map.tags !== -1 && cols[map.tags] ? cols[map.tags].split(',').map(t => t.trim()) : [],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            questionText: qText,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        options: { A: cols[map.a], B: cols[map.b], C: cols[map.c], D: cols[map.d] },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    correctAnswer: (cols[map.ans] || "").toUpperCase().trim(),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                explanation: map.expl !== -1 ? cols[map.expl] : ""
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    if (existingTextsSet.has(cleanText)) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                duplicatesDetected.push(qObject);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          } else {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      freshDetected.push(qObject);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  existingTextsSet.add(cleanText);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                setFreshQuestionsStack(freshDetected);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      setDuplicateQuestionsStack(duplicatesDetected);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              reader.readAsText(file);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const deployFreshData = async () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (freshQuestionsStack.length === 0) return alert("Bhai, deploy karne ke liye koi fresh questions nahi hain!");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          setIsUploading(true);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const metaRef = doc(db, "subject_meta", selectedSubjectForUpload);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const metaSnap = await getDoc(metaRef);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                let currentUnits = [], currentChunksConfig = {};
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (metaSnap.exists()) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              currentUnits = metaSnap.data().units || [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      currentChunksConfig = metaSnap.data().chunksConfig || {};
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const unitGroups = {};
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        freshQuestionsStack.forEach(q => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const unitName = q.unit[0];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (!unitGroups[unitName]) unitGroups[unitName] = [];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                unitGroups[unitName].push(q);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const batch = writeBatch(db);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const updatedUnits = [...new Set([...currentUnits, ...Object.keys(unitGroups)])];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        const updatedChunksConfig = { ...currentChunksConfig };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              for (const [unitName, qList] of Object.entries(unitGroups)) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const size = 200;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              let qIdx = 0;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      let chunkIdx = currentChunksConfig[unitName] || 0; 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      while (qIdx < qList.length) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const slice = qList.slice(qIdx, qIdx + size);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          batch.set(doc(db, "subject_meta", `${selectedSubjectForUpload}_${unitName}_chunk_${chunkIdx}`), { questions: slice });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    qIdx += size;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              chunkIdx++;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              updatedChunksConfig[unitName] = chunkIdx;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          batch.set(metaRef, { units: updatedUnits, chunksConfig: updatedChunksConfig, lastUpdated: Date.now() }, { merge: true });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                await batch.commit();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      alert(`🎉 Success! ${freshQuestionsStack.length} Fresh questions deployed!`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            setFreshQuestionsStack([]);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } catch (e) { alert("Error: " + e.message); }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    setIsUploading(false);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="min-h-screen bg-slate-100 text-left pb-12">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="bg-white p-4 sticky top-0 border-b z-50 flex items-center gap-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <button onClick={() => setIsSidebarOpen(true)} className="w-10 h-10 flex items-center justify-center bg-gray-100 rounded-full font-black text-xl">☰</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <h2 className="text-xl font-black text-gray-800">⚙️ MedACE Admin Control Room</h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="p-4 space-y-6 max-w-3xl mx-auto mt-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="bg-white p-6 rounded-[2.5rem] border space-y-4 shadow-xs">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <h3 className="text-base font-black text-slate-800 border-b pb-2">📦 Isolated Duplicate File Loader</h3>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="grid grid-cols-2 gap-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <label className="text-[10px] font-black uppercase text-gray-400 block mb-2">Subject Channel</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <select value={selectedSubjectForUpload} onChange={(e) => { setSelectedSubjectForUpload(e.target.value); setFreshQuestionsStack([]); setDuplicateQuestionsStack([]); }} className="w-full bg-gray-50 border p-3 rounded-xl font-bold text-xs">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <option value="">-- Choose Subject --</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {fixedSubjects.map(s => <option key={s.name} value={s.name}>{s.name}</option>)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </select>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <label className="text-[10px] font-black uppercase text-gray-400 block mb-2">Select CSV File</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <input type="file" accept=".csv" onChange={handleFileChange} className="w-full bg-gray-50 border p-2.5 rounded-xl text-xs font-bold" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {(freshQuestionsStack.length > 0 || duplicateQuestionsStack.length > 0) && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="p-4 bg-slate-50 rounded-2xl border space-y-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="flex justify-between items-center text-xs font-black">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <span className="text-green-600">🟢 Fresh Questions Found: {freshQuestionsStack.length}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <span className="text-red-500">🔴 Duplicates Isolated: {duplicateQuestionsStack.length}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <button onClick={deployFreshData} disabled={isUploading || freshQuestionsStack.length === 0} className="w-full bg-green-600 hover:bg-green-700 text-white font-black uppercase tracking-wider p-3.5 rounded-xl text-xs transition-all shadow-md">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {isUploading ? 'Deploying...' : `Deploy Only ${freshQuestionsStack.length} Fresh Questions`}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {duplicateQuestionsStack.length > 0 && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="bg-white p-6 rounded-[2.5rem] border border-red-200 space-y-3 shadow-xs">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <h3 className="text-sm font-black text-red-600 border-b border-red-100 pb-2 flex justify-between items-center">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <span>🔴 Isolated Duplicate Questions Review Stack</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <span className="text-xs bg-red-50 px-2.5 py-1 rounded-full">{duplicateQuestionsStack.length} MCQs</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </h3>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="max-h-60 overflow-y-auto border border-gray-100 rounded-2xl p-2 bg-gray-50/50 space-y-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {duplicateQuestionsStack.map((q, idx) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div key={idx} className="p-3 bg-white rounded-xl border border-red-100 text-[11px]">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="font-bold text-gray-400 uppercase text-[9px]">Unit: {q.unit[0]}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="font-semibold text-gray-800">Q: {q.questionText}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  export default AdminPanel;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  